Method.Source:
/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(ETG_Parameters, PurchParameters_ETGEstimationLedgerJournalName), FormControlEventType::Lookup)]
public static void PurchParameters_ETGEstimationLedgerJournalName_OnLookup(FormControl sender, FormControlEventArgs e)
{
    Query                   query = new Query();
    QueryBuildDataSource    queryBuildDataSource;
    SysTableLookup          sysTableLookup;

    sysTableLookup = SysTableLookup::newParameters(tableNum(LedgerJournalName), sender);
    queryBuildDataSource = query.addDataSource(tableNum(LedgerJournalName));
    queryBuildDataSource.addRange(fieldNum(LedgerJournalName, JournalType)).value(queryValue(LedgerJournalType::Daily));
    sysTableLookup.addLookupField(fieldNum(LedgerJournalName, JournalName), true);
    sysTableLookup.addLookupField(fieldNum(LedgerJournalName, Name));
    sysTableLookup.parmQuery(query);
    sysTableLookup.performFormLookup();
}

/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(ETG_Parameters, PurchParameters_ETGActualLedgerJournalName), FormControlEventType::Lookup)]
public static void PurchParameters_ETGActualLedgerJournalName1_OnLookup(FormControl sender, FormControlEventArgs e)
{
    Query                   query = new Query();
    QueryBuildDataSource    queryBuildDataSource;
    SysTableLookup          sysTableLookup;

    sysTableLookup       = SysTableLookup::newParameters(tableNum(LedgerJournalName), sender);
    queryBuildDataSource = query.addDataSource(tableNum(LedgerJournalName));
    queryBuildDataSource.addRange(fieldNum(LedgerJournalName, JournalType)).value(queryValue(LedgerJournalType::VendInvoiceRegister));
    sysTableLookup.addLookupField(fieldNum(LedgerJournalName, JournalName), true);
    sysTableLookup.addLookupField(fieldNum(LedgerJournalName, Name));
    sysTableLookup.parmQuery(query);
    sysTableLookup.performFormLookup();
}
